mapper.select:
/* 장치그룹내 장치목록 조회 */
select 
	device_id, site_id, user_idx, device_name, device_grp_idx, device_type, inst_type, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_device
where 1=1
and del_yn = 'N' 

and site_id =  #{siteId }


and device_grp_idx =  #{deviceGrpIdx }

/* 장치그룹내 장치들의 알람(미조치건) 조회 */
select 
	b.site_id, b.device_id, b.device_type, a.alarm_type, a.cnt, b.device_name
from (
	select 
		site_id, device_id, device_type, alarm_type, count(*) as cnt
	from tb_alarm
	where 1=1
	and alarm_act_yn = 'N'
	and alarm_type = #{alarmType }
	group by site_id, device_id, device_type, alarm_type
) a left outer join tb_device b
on a.site_id = b.site_id
and a.device_id = b.device_id
and a.device_type = b.device_type
where b.site_id = #{siteId }
and b.device_grp_idx = #{deviceGrpIdx }

/* 장치목록(사이트 전체 장치 중 특정 장치그룹 제외) 조회 */ select device_id, site_id, user_idx, device_name, device_grp_idx, device_type, inst_type, del_yn, reg_uid, reg_date, mod_uid, mod_date from tb_device where 1=1 and del_yn = 'N'
and site_id = #{siteId }
and (device_grp_idx != #{deviceGrpIdx } or device_grp_idx is null)

mapper.delete:
/* 장치그룹 삭제 */
delete from tb_device_group
where 1=1
and device_grp_idx = #{deviceGrpIdx }

mapper.insert:
/* 장치그룹 등록 */ insert into tb_device_group (
site_id, user_idx, device_grp_name, del_yn, reg_uid, reg_date ) values (
#{siteId }, #{userIdx }, #{deviceGrpName }, 'N', #{regUid }, now() )

mapper.select:
/* 장치 중복여부 체크 */
select 
	count(*) as cnt 
from tb_device
where 1=1
and site_id = #{siteId }
and device_id = #{deviceId }
and device_type = #{deviceType }

mapper.update:
/* 장치 수정 */
update tb_device
set 
    
     
    device_name    = #{deviceName }, 
    
     
    device_grp_idx = #{deviceGrpIdx }, 
    
     
    device_type    = #{deviceType }, 
    
     
    inst_type      = #{instType }, 
    
    mod_uid        = #{modUid }, 
    mod_date       = now()
where 1=1
and site_id = #{siteId }
and device_id = #{deviceId }
and device_type = #{deviceType }

mapper.delete:
/* 장치 삭제 */
delete from tb_device
where 1=1
and site_id = #{siteId }
and device_id = #{deviceId }
and device_type = #{deviceType }
